详细阅读binance的自定义指标文档md文件，//@version=6
indicator("Segment ATR Dynamic Trailing Exit", overlay = true)

atrLength = input.int(14, "ATR Length")
atrMult = input.float(5.25, "ATR Multiplier", step = 0.25)

atr = ta.atr(atrLength)

//=============================
// 状态变量
//=============================
var float highestHigh = na
var float stopLine = na

// 下一根开始新的 Segment
var bool newSegment = false

// 绘图变量
float plotStop = na
color plotColor = color.lime

//=============================
// 初始化
//=============================
if na(stopLine) and not newSegment
highestHigh := high
stopLine := high - atr * atrMult
plotStop := stopLine
plotColor := color.lime

//=============================
// 新 Segment（上一根跌破）
//=============================
else if newSegment

highestHigh := high
stopLine := high - atr * atrMult

plotStop := stopLine
plotColor := color.lime

newSegment := false

//=============================
// 正常追踪
//=============================
else

// 跌破止损
if close <= stopLine

// 最后一格保留，但变灰
plotStop := stopLine
plotColor := color.new(color.gray, 65)

stopLine := na
highestHigh := na

newSegment := true

else

// 本段最高价
highestHigh := math.max(highestHigh, high)

// 本段动态止损
dynamicStop = highestHigh - atr * atrMult

// 止损只能抬高
stopLine := math.max(stopLine, dynamicStop)

plotStop := stopLine
plotColor := color.lime

//=============================
// 绘图
//=============================
plot(
plotStop,
title = "Segment ATR Trailing Stop",
color = plotColor,
linewidth = 2,
style = plot.style_stepline
)将这个tradingview改为binance版本，注binance自定义的注释是#
